function CompassMark({ size = 260, className = "", spin = false }) {
  return (
    <svg viewBox="0 0 200 200" width={size} height={size} className={`${className} ${spin ? "spin-slow" : ""}`} style={{ opacity: 0.14 }}>
      <circle cx="100" cy="100" r="96" fill="none" stroke="#C6A15B" strokeWidth="0.6" />
      <circle cx="100" cy="100" r="80" fill="none" stroke="#C6A15B" strokeWidth="0.4" />
      {Array.from({ length: 8 }).map((_, i) => {
        const angle = (i * 45 * Math.PI) / 180;
        const x1 = 100 + 96 * Math.cos(angle), y1 = 100 + 96 * Math.sin(angle);
        const x2 = 100 + 30 * Math.cos(angle), y2 = 100 + 30 * Math.sin(angle);
        return <line key={i} x1={x1} y1={y1} x2={x2} y2={y2} stroke="#C6A15B" strokeWidth="0.5" />;
      })}
      <polygon points="100,10 112,100 100,190 88,100" fill="#C6A15B" opacity="0.5" />
      <polygon points="10,100 100,88 190,100 100,112" fill="#C6A15B" opacity="0.3" />
    </svg>
  );
}

/* شكل هندسي أصلي مستوحى من قبة ومئذنتَي مرقد شريف، ضمن إطار نجمي ثماني (رسم أصلي وليس صورة فوتوغرافية) */
function ShrineMark({ size = 260, className = "", spin = false }) {
  return (
    <svg viewBox="0 0 200 200" width={size} height={size} className={`${className} ${spin ? "spin-slow" : ""}`} style={{ opacity: 0.16 }}>
      <circle cx="100" cy="100" r="96" fill="none" stroke="#C6A15B" strokeWidth="0.6" />
      <circle cx="100" cy="100" r="80" fill="none" stroke="#C6A15B" strokeWidth="0.4" />
      {Array.from({ length: 8 }).map((_, i) => {
        const angle = (i * 45 * Math.PI) / 180;
        const x1 = 100 + 96 * Math.cos(angle), y1 = 100 + 96 * Math.sin(angle);
        const x2 = 100 + 62 * Math.cos(angle), y2 = 100 + 62 * Math.sin(angle);
        return <line key={i} x1={x1} y1={y1} x2={x2} y2={y2} stroke="#C6A15B" strokeWidth="0.5" />;
      })}
      {/* مئذنة يسار */}
      <rect x="52" y="90" width="7" height="55" fill="#C6A15B" opacity="0.55" />
      <polygon points="55.5,78 60,90 51,90" fill="#C6A15B" opacity="0.55" />
      {/* مئذنة يمين */}
      <rect x="141" y="90" width="7" height="55" fill="#C6A15B" opacity="0.55" />
      <polygon points="144.5,78 149,90 140,90" fill="#C6A15B" opacity="0.55" />
      {/* القبة المركزية */}
      <path d="M78 145 V110 Q78 78 100 70 Q122 78 122 110 V145 Z" fill="#C6A15B" opacity="0.6" />
      <circle cx="100" cy="62" r="4" fill="#C6A15B" opacity="0.6" />
      <rect x="99" y="50" width="2" height="12" fill="#C6A15B" opacity="0.6" />
      <rect x="70" y="145" width="60" height="6" fill="#C6A15B" opacity="0.4" />
    </svg>
  );
}

