function Splash({ onDone }) {
  const [leaving, setLeaving] = useState(false);
  useEffect(() => {
    const t1 = setTimeout(() => setLeaving(true), 1700);
    const t2 = setTimeout(onDone, 2150);
    return () => { clearTimeout(t1); clearTimeout(t2); };
  }, [onDone]);
  return (
    <div onClick={() => { setLeaving(true); setTimeout(onDone, 400); }} className="fixed inset-0 z-[100] flex flex-col items-center justify-center transition-opacity duration-500"
      style={{ background: "radial-gradient(circle at 50% 30%, #14261B, #060B08 75%)", opacity: leaving ? 0 : 1, pointerEvents: leaving ? "none" : "auto" }}>
      <ShrineMark size={340} className="absolute" spin />
      <div className="pop-in flex flex-col items-center gap-4">
        <div className="rounded-full overflow-hidden glow-pulse" style={{ width: 156, height: 156, boxShadow: "0 0 60px #C6A15B55, 0 0 0 1px #C6A15B55" }}>
          <img src={LOGO_SRC} alt="شعار الهيئة" className="w-full h-full object-cover" />
        </div>
        <div className="text-center mt-2">
          <div style={{ fontFamily: "'Aref Ruqaa', serif", fontSize: 26, color: "#F3EEDF" }}>هيئة الشيخ أحمد الوائلي</div>
          <div className="text-xs tracking-[0.3em] mt-1" style={{ color: "#C6A15B" }}>ثقافية — توعوية</div>
        </div>
      </div>
      <div className="absolute bottom-10 text-[11px]" style={{ color: "#5C6B60" }}>رحمه الله</div>
    </div>
  );
}

