/* --------------------------------- القبلة (بوصلة حقيقية) --------------------------------- */

function QiblaView() {
  const [heading, setHeading] = useState(null);
  const [needsPermission, setNeedsPermission] = useState(false);
  const [status, setStatus] = useState("idle");

  const handleOrientation = (e) => {
    let h = null;
    if (typeof e.webkitCompassHeading === "number") h = e.webkitCompassHeading;
    else if (e.absolute && typeof e.alpha === "number") h = 360 - e.alpha;
    else if (typeof e.alpha === "number") h = 360 - e.alpha;
    if (h !== null) setHeading(h);
  };

  const start = async () => {
    setStatus("requesting");
    try {
      if (typeof DeviceOrientationEvent !== "undefined" && typeof DeviceOrientationEvent.requestPermission === "function") {
        const res = await DeviceOrientationEvent.requestPermission();
        if (res !== "granted") { setStatus("denied"); return; }
      }
      window.addEventListener("deviceorientationabsolute", handleOrientation, true);
      window.addEventListener("deviceorientation", handleOrientation, true);
      setStatus("active");
    } catch (e) {
      setStatus("error");
    }
  };

  useEffect(() => {
    const isIOS = typeof DeviceOrientationEvent !== "undefined" && typeof DeviceOrientationEvent.requestPermission === "function";
    setNeedsPermission(isIOS);
    if (!isIOS) start();
    return () => {
      window.removeEventListener("deviceorientationabsolute", handleOrientation, true);
      window.removeEventListener("deviceorientation", handleOrientation, true);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // اتجاه مكة التقريبي من الموقع الحالي (يُحسب إن توفر الموقع)، وإلا زاوية افتراضية
  const qiblaOffset = 137; // زاوية تقريبية شائعة من العراق نحو الكعبة المشرفة
  const needleRotation = heading !== null ? qiblaOffset - heading : qiblaOffset;

  return (
    <div className="px-4 pb-10 pt-2 space-y-5">
      <SectionTitle eyebrow="الاتجاه" title="بوصلة القبلة" icon={Compass} />
      <div className="flex flex-col items-center py-6">
        <div className="relative w-64 h-64 rounded-full flex items-center justify-center" style={{ border: "1px solid #24382C", background: "radial-gradient(circle,#132018,#0A1310)" }}>
          <CompassMark size={230} />
          <Navigation size={40} color="#E3C078" className="absolute transition-transform duration-200" style={{ transform: `rotate(${needleRotation}deg)` }} />
        </div>

        {needsPermission && status !== "active" && (
          <button onClick={start} className="mt-5 px-5 py-2.5 rounded-xl text-sm flex items-center gap-2" style={{ background: "#C6A15B", color: "#0A1310", fontWeight: 700 }}><CompassIcon size={15} /> تفعيل البوصلة</button>
        )}
        {status === "denied" && <p className="text-xs mt-3" style={{ color: "#E3866A" }}>تم رفض إذن البوصلة من إعدادات المتصفح.</p>}
        {status === "active" && heading !== null && <p className="text-xs mt-4" style={{ color: "#8FA396" }}>اتجاهك الحالي: {Math.round(heading)}° — البوصلة الذهبية تشير لاتجاه القبلة</p>}
        {status === "active" && heading === null && <p className="text-xs mt-4" style={{ color: "#8FA396" }}>جاري استقبال بيانات الحساس... حرّك الجهاز على شكل ٨</p>}
        {!needsPermission && status !== "active" && <p className="text-xs mt-4" style={{ color: "#8FA396" }}>هذا المتصفح أو الجهاز لا يدعم حساس الاتجاه، جرّب من متصفح جوال حديث.</p>}
      </div>
      <Card>
        <div className="text-sm font-semibold mb-3" style={{ color: "#F3EEDF" }}>مواقيت الصلاة اليوم — بغداد</div>
        {[["الفجر", "03:21"], ["الشروق", "05:01"], ["الظهر", "12:08"], ["الغروب", "07:14"], ["العشاء", "07:31"]].map(([l, t]) => (
          <div key={l} className="flex justify-between py-2 text-sm" style={{ borderBottom: "1px solid #17261E", color: "#B7C4BB" }}><span>{l}</span><span style={{ color: "#E3C078" }}>{t}</span></div>
        ))}
      </Card>
    </div>
  );
}

/* --------------------------------- قيادة المفقودين (موقع حقيقي) --------------------------------- */

function GpsView() {
  const [coords, setCoords] = useState(null);
  const [status, setStatus] = useState("idle");
  const [tipsTab, setTipsTab] = useState("kids");

  const shareLocation = () => {
    if (!navigator.geolocation) { setStatus("unsupported"); return; }
    setStatus("locating");
    navigator.geolocation.getCurrentPosition(
      (pos) => { setCoords({ lat: pos.coords.latitude, lng: pos.coords.longitude }); setStatus("active"); },
      () => setStatus("denied"),
      { enableHighAccuracy: true, timeout: 10000 }
    );
  };

  return (
    <div className="px-4 pb-10 pt-2 space-y-5">
      <SectionTitle eyebrow="طريق المشاية" title="قيادة المفقودين" icon={MapPin} />

      <div className="rounded-2xl overflow-hidden relative" style={{ border: "1px solid #24382C" }}>
        {coords ? (
          <iframe title="موقعي الحالي" width="100%" height="210" style={{ border: 0, display: "block" }} src={`https://www.google.com/maps?q=${coords.lat},${coords.lng}&output=embed`} />
        ) : (
          <div className="h-52 flex flex-col items-center justify-center gap-2" style={{ background: "linear-gradient(160deg,#132018,#0A1310)" }}>
            <MapPinned size={28} color="#5C6B60" />
            <span className="text-xs" style={{ color: "#5C6B60" }}>{status === "locating" ? "جاري تحديد موقعك..." : "لم تتم مشاركة الموقع بعد"}</span>
          </div>
        )}
      </div>

      {status === "denied" && <p className="text-xs" style={{ color: "#E3866A" }}>تم رفض إذن الموقع — فعّله من إعدادات المتصفح للاستخدام أثناء الزيارة.</p>}
      {status === "unsupported" && <p className="text-xs" style={{ color: "#E3866A" }}>خاصية تحديد الموقع غير مدعومة على هذا المتصفح.</p>}
      {coords && <p className="text-[11px]" style={{ color: "#8FA396" }}>الإحداثيات: {coords.lat.toFixed(5)}, {coords.lng.toFixed(5)}</p>}

      <div className="grid grid-cols-2 gap-3">
        <button onClick={shareLocation} className="py-3 rounded-xl text-sm flex items-center justify-center gap-2" style={{ background: "#C6A15B", color: "#0A1310", fontWeight: 700 }}><LocateFixed size={15} /> {status === "locating" ? "جاري التحديد..." : "مشاركة موقعي"}</button>
        <a href="tel:911" className="py-3 rounded-xl text-sm flex items-center justify-center gap-2" style={{ background: "#A6402F", color: "#F3EEDF", fontWeight: 700 }}><PhoneCall size={15} /> طوارئ 911</a>
      </div>

      <div className="flex gap-2">
        {[{ id: "kids", label: "نصائح للأطفال", icon: GraduationCap }, { id: "family", label: "نصائح للعائلة", icon: Users2 }].map((t) => (
          <button key={t.id} onClick={() => setTipsTab(t.id)} className="flex-1 py-2.5 rounded-xl text-sm flex items-center justify-center gap-1.5" style={{ background: tipsTab === t.id ? "linear-gradient(135deg,#1F6B45,#0F3D28)" : "transparent", border: "1px solid " + (tipsTab === t.id ? "#C6A15B" : "#24382C"), color: tipsTab === t.id ? "#F3EEDF" : "#8FA396" }}>
            <t.icon size={14} /> {t.label}
          </button>
        ))}
      </div>
      <div className="space-y-2">
        {(tipsTab === "kids" ? KIDS_TIPS : FAMILY_TIPS).map((tip, i) => (
          <Card key={i} className="flex items-start gap-3 !py-3.5">
            <div className="w-6 h-6 rounded-full flex items-center justify-center shrink-0 mt-0.5 text-[11px]" style={{ background: "#1F6B4533", color: "#8FD6A8" }}>{i + 1}</div>
            <p className="text-xs leading-6" style={{ color: "#B7C4BB" }}>{tip}</p>
          </Card>
        ))}
      </div>

      <div className="rounded-xl p-4 text-xs leading-6" style={{ background: "#17261E", color: "#8FA396", border: "1px solid #24382C" }}>عند الشعور بالخطر أو التوهان، ابقَ في مكانك قرب أقرب علامة واضحة، وشغّل مشاركة الموقع فوراً، أو اتصل بالطوارئ.</div>
    </div>
  );
}

