/* --------------------------------- خلفيات ونغمات (رفع إداري) --------------------------------- */

function MediaView({ isAdmin, requestAdmin }) {
  const [wallpapers, setWallpapers] = useState([]);
  const [uploading, setUploading] = useState(false);
  const fileRef = useRef(null);

  useEffect(() => {
    (async () => {
      try { const res = await storage.get("hayaa_wallpapers"); if (res && res.value) setWallpapers(JSON.parse(res.value)); } catch (e) {}
    })();
  }, []);

  const persist = async (arr) => { try { await storage.set("hayaa_wallpapers", JSON.stringify(arr)); } catch (e) { console.error(e); } };

  const handleUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setUploading(true);
    const reader = new FileReader();
    reader.onload = async () => {
      const arr = [{ id: Date.now().toString(), src: reader.result }, ...wallpapers];
      setWallpapers(arr); await persist(arr); setUploading(false);
    };
    reader.readAsDataURL(file);
  };

  const remove = async (id) => { const arr = wallpapers.filter((w) => w.id !== id); setWallpapers(arr); await persist(arr); };

  return (
    <div className="px-4 pb-10 pt-2 space-y-5">
      <SectionTitle eyebrow="تحميل" title="خلفيات ونغمات" icon={ImageIcon} />

      {isAdmin ? (
        <Card style={{ border: "1px solid #C6A15B55" }}>
          <div className="text-xs mb-3 flex items-center gap-2" style={{ color: "#C6A15B" }}><Lock size={13} /> رفع خلفية جديدة — إدارة الهيئة</div>
          <input ref={fileRef} type="file" accept="image/*" onChange={handleUpload} className="hidden" />
          <button onClick={() => fileRef.current.click()} disabled={uploading} className="w-full py-2.5 rounded-xl text-sm flex items-center justify-center gap-2" style={{ background: "#C6A15B", color: "#0A1310", fontWeight: 700 }}><Upload size={14} /> {uploading ? "جاري الرفع..." : "اختيار صورة ورفعها"}</button>
        </Card>
      ) : (
        <AdminGate onSuccess={requestAdmin} />
      )}

      <div className="grid grid-cols-3 gap-2">
        {wallpapers.length === 0 && <div className="col-span-3 text-center text-xs py-6" style={{ color: "#5C6B60" }}>لا توجد خلفيات مرفوعة بعد.</div>}
        {wallpapers.map((w) => (
          <div key={w.id} className="relative aspect-[3/4] rounded-xl overflow-hidden">
            <img src={w.src} alt="خلفية" className="w-full h-full object-cover" />
            {isAdmin && <button onClick={() => remove(w.id)} className="absolute top-1 left-1 w-6 h-6 rounded-full flex items-center justify-center" style={{ background: "#0A1310cc" }}><Trash2 size={12} color="#E3866A" /></button>}
          </div>
        ))}
      </div>

      <SectionTitle eyebrow="صوت" title="نغمات الإشعارات" icon={Music2} />
      <div className="space-y-2">
        {["نداء الفجر", "أذان الحرم العلوي", "تنبيه هادئ"].map((t) => (
          <Card key={t} className="flex items-center justify-between !py-3.5"><span className="text-sm" style={{ color: "#F3EEDF" }}>{t}</span><div className="w-8 h-8 rounded-full flex items-center justify-center" style={{ background: "#1F6B4533" }}><Music2 size={14} color="#E3C078" /></div></Card>
        ))}
      </div>
    </div>
  );
}

/* --------------------------------- الإعدادات --------------------------------- */

function SettingsView() {
  return (
    <div className="px-4 pb-10 pt-2 space-y-5">
      <SectionTitle eyebrow="تخصيص" title="الإعدادات" icon={Settings} />
      {["اللغة", "الإشعارات", "طريقة حساب المواقيت", "المذهب الفقهي", "عن الهيئة"].map((s) => (
        <Card key={s} className="flex items-center justify-between !py-4"><span className="text-sm" style={{ color: "#F3EEDF" }}>{s}</span><ChevronLeft size={16} color="#8FA396" /></Card>
      ))}
    </div>
  );
}

/* ------------------------------------- التطبيق ------------------------------------- */

export default function App() {
  const [showSplash, setShowSplash] = useState(true);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [active, setActive] = useState("home");
  const [dateMode, setDateMode] = useState("hijri");
  const [posts, setPosts] = useState([]);
  const [isAdmin, setIsAdmin] = useState(false);

  useEffect(() => {
    (async () => {
      try { const res = await storage.get("hayaa_posts"); if (res && res.value) setPosts(JSON.parse(res.value)); } catch (e) {}
    })();
  }, []);

  const gregorian = new Date().toLocaleDateString("ar-IQ", { weekday: "long", year: "numeric", month: "long", day: "numeric" });
  const hijri = "٢٥ محرم ١٤٤٨ هـ";

  const views = {
    home: <HomeView gregorian={gregorian} hijri={hijri} posts={posts} goTo={setActive} />,
    posts: <PostsView posts={posts} setPosts={setPosts} isAdmin={isAdmin} requestAdmin={() => setIsAdmin(true)} />,
    calendar: <CalendarView />,
    quran: <QuranView />,
    supplications: <SupplicationsView />,
    rosary: <RosaryView />,
    prayers: <PrayersView />,
    qibla: <QiblaView />,
    gps: <GpsView />,
    notebook: <NotebookView />,
    steps: <StepsView />,
    media: <MediaView isAdmin={isAdmin} requestAdmin={() => setIsAdmin(true)} />,
    settings: <SettingsView />,
  };

  return (
    <div dir="rtl" className="min-h-screen w-full" style={{ background: "#0A1310", fontFamily: "'Cairo', sans-serif" }}>
      <style>{FONTS}</style>
      {showSplash && <Splash onDone={() => setShowSplash(false)} />}
      <div className="max-w-md mx-auto min-h-screen relative" style={{ boxShadow: "0 0 60px #00000066" }}>
        <Header onMenu={() => setSidebarOpen(true)} dateMode={dateMode} setDateMode={setDateMode} gregorian={gregorian} hijri={hijri} />
        <Sidebar open={sidebarOpen} onClose={() => setSidebarOpen(false)} active={active} setActive={setActive} />
        {views[active]}
        <div className="sticky bottom-0 left-0 right-0 px-4 pb-3">
          <div className="flex items-center justify-around py-2.5 rounded-2xl" style={{ background: "rgba(13,23,18,0.92)", backdropFilter: "blur(14px)", border: "1px solid #1C2B22" }}>
            {[{ id: "home", icon: Sparkles, label: "الرئيسية" }, { id: "posts", icon: Megaphone, label: "المنشورات" }, { id: "gps", icon: MapPin, label: "المفقودين" }, { id: "rosary", icon: RotateCcw, label: "المسبحة" }, { id: "calendar", icon: CalendarDays, label: "التقويم" }].map((n) => {
              const Icon = n.icon; const isActive = active === n.id;
              return (<button key={n.id} onClick={() => setActive(n.id)} className="flex flex-col items-center gap-1 px-2"><Icon size={18} color={isActive ? "#E3C078" : "#5C6B60"} /><span className="text-[10px]" style={{ color: isActive ? "#E3C078" : "#5C6B60" }}>{n.label}</span></button>);
            })}
          </div>
        </div>
      </div>
    </div>
  );
}
